parameters.jsCode:
const raw = $json.message?.content || $json.response || '';
let blog;

try {
  blog = JSON.parse(raw);
} catch (error) {
  throw new Error(`Model returned invalid JSON: ${raw.slice(0, 800)}`);
}

function trimTo(value, max) {
  return String(value || '').trim().slice(0, max);
}

function ensureArray(value) {
  if (Array.isArray(value)) return value.map(v => String(v).trim()).filter(Boolean);
  if (typeof value === 'string') return value.split(',').map(v => v.trim()).filter(Boolean);
  return [];
}

const content = String(blog.contentHtml || blog.content || '').trim();
const wordCount = content.replace(/<[^>]*>/g, ' ').split(/\s+/).filter(Boolean).length;

if (!blog.title || !content || !blog.excerpt) {
  throw new Error('Blog output missing title, excerpt, or contentHtml.');
}

if (wordCount < 700) {
  throw new Error(`Blog content too short: ${wordCount} words.`);
}

return [{
  json: {
    title: trimTo(blog.title, 120),
    excerpt: trimTo(blog.excerpt, 300),
    content,
    featuredImage: null,
    categories: ensureArray(blog.categories),
    tags: ensureArray(blog.tags),
    seo: {
      metaTitle: trimTo(blog.seo?.metaTitle || blog.title, 60),
      metaDescription: trimTo(blog.seo?.metaDescription || blog.excerpt, 160),
      keywords: ensureArray(blog.seo?.keywords)
    },
    status: 'draft',
    sourceKeyword: $('Split Topics').item.json.keyword,
    sourceLocation: $('Split Topics').item.json.location,
    wordCount
  }
}];

